// ---- GitHub lead scraper: find B2B SaaS founders -> POST to lead-ingest pipeline ----
const ENV = (typeof $env !== 'undefined' && $env) ? $env : process.env;
const GH = ENV.GITHUB_TOKEN;
const WEBHOOK = ENV.N8N_WEBHOOK_URL || "http://localhost:5678/webhook/lead-ingest";
const headers = { Authorization: "Bearer " + GH, Accept: "application/vnd.github+json", "User-Agent": "markexis-scraper" };
const CAP = 6; // leads per run (keep small; each triggers full enrich+score pipeline)
const queries = ["topic:saas stars:80..1500", "topic:b2b-saas stars:30..1200"];

let posted = 0, skipped = 0; const errors = []; const seen = new Set(); const results = [];
for (const q of queries) {
  if (seen.size >= CAP) break;
  let repos = [];
  try {
    const r = await this.helpers.httpRequest({ method: "GET",
      url: "https://api.github.com/search/repositories?sort=stars&order=desc&per_page=15&q=" + encodeURIComponent(q),
      headers, json: true, timeout: 20000 });
    repos = (r && r.items) || [];
  } catch (e) { errors.push("search: " + String(e && e.message || e).slice(0,120)); continue; }

  for (const repo of repos) {
    if (seen.size >= CAP) break;
    const owner = repo.owner || {};
    if (owner.type !== "User") { skipped++; continue; }
    if (seen.has(owner.login)) continue;
    seen.add(owner.login);
    let u = {};
    try { u = await this.helpers.httpRequest({ method: "GET", url: "https://api.github.com/users/" + owner.login, headers, json: true, timeout: 15000 }); }
    catch (e) { errors.push("user " + owner.login); continue; }

    const company = (u.company || "").replace(/^@/, "").trim() || repo.name;
    const blog = (u.blog || "").trim();
    const lead = {
      name: u.name || owner.login,
      email: u.email || null,
      company,
      domain: blog || null,
      title: "Founder / Maintainer",
      location: u.location || null,
      source_platform: "github",
      source_url: u.html_url,
      raw_bio: [u.bio, "Maintains " + repo.full_name + " (" + repo.stargazers_count + " stars). " + (repo.description || "")].filter(Boolean).join(" | "),
      company_size_signal: "unknown",
      scraped_at: new Date().toISOString()
    };
    try {
      const resp = await this.helpers.httpRequest({ method: "POST", url: WEBHOOK, headers: { "Content-Type": "application/json" }, body: lead, json: true, timeout: 90000 });
      posted++;
      results.push({ login: owner.login, company, score: (resp && resp.summary) ? resp.summary.icp_score : "?" });
    } catch (e) { errors.push("post " + owner.login + ": " + String(e && e.message || e).slice(0,80)); }
  }
}
return [{ json: { posted, skipped, checked: seen.size, errors: errors.slice(0,5), results } }];
